class FilterStore {
  constructor(options = {}) {
    this.cachePath = options.cachePath || DEFAULT_CACHE_PATH;
    this.data = emptyData();
    this.blockedDomainSet = new Set();
    this.refreshPromise = null;
    this.refreshTimer = null;

    this._loadFromDiskSync();
  }

  _loadFromDiskSync() {
    try {
      if (existsSync(this.cachePath)) {
        const raw = readFileSync(this.cachePath, 'utf8');
        const parsed = JSON.parse(raw);
        this._applyData(parsed);
      }
    } catch (error) {
      // Corrupt or unreadable cache file — start empty, a refresh will fix it.
      // eslint-disable-next-line no-console
      console.error(`[adblock] Failed to load cache from disk: ${error.message}`);
    }
  }

  _persistToDiskSync() {
    try {
      mkdirSync(dirname(this.cachePath), { recursive: true });
      writeFileSync(this.cachePath, JSON.stringify(this.data), 'utf8');
    } catch (error) {
      // eslint-disable-next-line no-console
      console.error(`[adblock] Failed to persist cache to disk: ${error.message}`);
    }
  }

_applyData(data) {
    const defaults = emptyData(); // Retrieve your hardcoded list

    this.data = {
      // Merge your default domains with the incoming (cache/network) domains, removing duplicates
      blockedDomains: Array.from(new Set([
        ...defaults.blockedDomains,
        ...(data.blockedDomains || [])
      ])),
      exceptionDomains: data.exceptionDomains || [],
      globalCssSelectors: data.globalCssSelectors || [],
      domainSpecificCss: data.domainSpecificCss || {},
      domainCssExceptions: data.domainCssExceptions || {},
      generatedAt: data.generatedAt || null,
      sourceFiles: data.sourceFiles || [],
    };
    
    this.blockedDomainSet = new Set(this.data.blockedDomains);
  }

  /**
   * Loads pre-parsed filter data directly (used by tests, or by callers
   * who fetched the data themselves).
   */
  loadData(data) {
    this._applyData(data);
    this._persistToDiskSync();
  }

  /**
   * Fetches fresh filter lists from the network and updates the store.
   * Safe to call concurrently — concurrent calls share the same in-flight
   * request rather than firing duplicate network calls.
   */
  async refresh(options = {}) {
    if (this.refreshPromise) return this.refreshPromise;

    this.refreshPromise = (async () => {
      const data = await fetchAndParseFilters(options);
      this._applyData(data);
      this._persistToDiskSync();
      return data;
    })();

    try {
      return await this.refreshPromise;
    } finally {
      this.refreshPromise = null;
    }
  }

  /**
   * Starts a periodic background refresh. Returns a function to stop it.
   */
  startAutoRefresh(intervalMs = 12 * 60 * 60 * 1000, options = {}) {
    this.stopAutoRefresh();
    this.refreshTimer = setInterval(() => {
      this.refresh(options).catch((error) => {
        // eslint-disable-next-line no-console
        console.error(`[adblock] Background refresh failed: ${error.message}`);
      });
    }, intervalMs);
    return () => this.stopAutoRefresh();
  }

  stopAutoRefresh() {
    if (this.refreshTimer) {
      clearInterval(this.refreshTimer);
      this.refreshTimer = null;
    }
  }

  isReady() {
    return this.data.generatedAt !== null;
  }
}

export { FilterStore, DEFAULT_CACHE_PATH, emptyData };